const https = require('https');
const urlMod = require('url');
function httpReq(method, rawUrl, headers, postBody) {
  return new Promise((resolve, reject) => {
    const parsed = urlMod.parse(rawUrl);
    const opts = { hostname: parsed.hostname, path: parsed.path, method: method, headers: headers || {} };
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        let json = null;
        try { json = JSON.parse(body); } catch(e) {}
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, json: json, text: body });
      });
    });
    req.on('error', reject);
    if (postBody) req.write(typeof postBody === 'string' ? postBody : JSON.stringify(postBody));
    req.end();
  });
}

// Dashboard Feed: pulls all GHL opportunities and writes to Google Sheets
const GHL_TOKEN = '{{ghl_token}}';
const LOCATION_ID = '{{ghl_location_id}}';
const SHEET_ID = '{{sheet_id}}';
const BASE = 'https://services.leadconnectorhq.com';
const HEADERS = { 'Authorization': `Bearer ${GHL_TOKEN}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' };

const FIELD_IDS = {
  labor_budget: '{{ghl_cf_labor_budget}}',
  crew_payout: '{{ghl_cf_crew_payout}}',
  gross_margin_pct: '{{ghl_cf_gross_margin_pct}}',
  product_type: '{{ghl_cf_product_type}}',
  material_cost: '{{ghl_cf_material_cost}}',
  material_order_total: '{{ghl_cf_material_order_total}}',
  crew: '{{ghl_cf_crew}}',
  labor_cap_pct: '{{ghl_cf_labor_cap_pct}}'
};

// Fetch all opportunities
let allOpps = [];
let hasMore = true;
let startAfter = '';
while (hasMore) {
  const params = `?location_id=${LOCATION_ID}&limit=100${startAfter ? '&startAfter=' + startAfter : ''}`;
  const resp = await httpReq('GET', `${BASE}/opportunities/search${params}`, HEADERS );
  const data = await resp.json;
  if (!resp.ok || !data.opportunities?.length) { hasMore = false; break; }
  allOpps = allOpps.concat(data.opportunities);
  if (data.meta?.startAfter) startAfter = data.meta.startAfter;
  else hasMore = false;
  if (data.opportunities.length < 100) hasMore = false;
}

// Map to dashboard format
const jobs = allOpps.map(opp => {
  const cf = opp.customFields || [];
  const getField = (key) => {
    const f = cf.find(x => x.id === FIELD_IDS[key]);
    return f ? f.value : '';
  };
  return {
    id: opp.id,
    name: opp.name || '',
    client: opp.contact?.name || '',
    status: opp.status || 'open',
    stage: opp.pipelineStageId || '',
    value: parseFloat(opp.monetaryValue) || 0,
    margin: parseFloat(getField('gross_margin_pct')) || 0,
    labor_budget: parseFloat(getField('labor_budget')) || 0,
    labor_cost: parseFloat(getField('crew_payout')) || 0,
    material_cost: parseFloat(getField('material_cost')) || 0,
    product_type: getField('product_type'),
    crew: getField('crew'),
    date_created: opp.dateAdded || '',
    last_updated: opp.dateUpdated || ''
  };
});

// Calculate net profit per job
jobs.forEach(j => {
  j.net_profit = j.value - j.labor_cost - j.material_cost;
});

return [{ json: { jobs, count: jobs.length, updated: new Date().toISOString() } }];
